#include <bits/stdc++.h>
using namespace std;
const int maxn=15;
const double eps=1e-6;
int n;
double l,r,a[maxn];
double f(double x){
	double s=0;
	for(int i=0;i<=n;i++){
		s=s*x+a[i];
	}
	return s;
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>l>>r;
	for(int i=0;i<=n;i++){
		cin>>a[i];
	}
	while(r-l>=eps){
		double mid1=l+(r-l)/3.0,mid2=r-(r-l)/3.0;
		if(f(mid1)>f(mid2)){
			r=mid2;
		}else{
			l=mid1;
		}
	}
	cout<<fixed<<setprecision(5)<<l;
	return 0;
}
